### 3-2. Redis 캐시 설정

파일 위치: `{module}/src/main/kotlin/com/maum/backend/config/CacheConfig.kt`

```kotlin
@Configuration
@EnableCaching
class CacheConfig {

    companion object {
        // 캐시 이름 상수 - 오타 방지
        const val CACHE_USER_PROFILE    = "userProfile"
        const val CACHE_MANNER_SCORE    = "mannerScore"
        const val CACHE_FOLLOW_STATUS   = "followStatus"
        const val CACHE_NOTIF_SETTING   = "notificationSetting"
        const val CACHE_LIKE_COUNT      = "likeCount"
        const val CACHE_CATEGORY_CODES  = "categoryCodes"
    }

    @Bean
    fun redisConnectionFactory(
        @Value("\${spring.redis.host}") host: String,
        @Value("\${spring.redis.port}") port: Int,
    ): RedisConnectionFactory {
        return LettuceConnectionFactory(host, port)
    }

    @Bean
    fun cacheManager(redisConnectionFactory: RedisConnectionFactory): CacheManager {
        val objectMapper = ObjectMapper().apply {
            registerModule(KotlinModule.Builder().build())
            activateDefaultTyping(
                LaissezFaireSubTypeValidator.instance,
                ObjectMapper.DefaultTyping.NON_FINAL,
                JsonTypeInfo.As.PROPERTY,
            )
            configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, false)
        }

        val jsonSerializer = GenericJackson2JsonRedisSerializer(objectMapper)

        // 캐시별 TTL 설정
        val configurations = mapOf(
            CACHE_USER_PROFILE   to ttl(minutes = 30),
            CACHE_MANNER_SCORE   to ttl(minutes = 60),
            CACHE_FOLLOW_STATUS  to ttl(minutes = 10),
            CACHE_NOTIF_SETTING  to ttl(hours = 24),
            CACHE_LIKE_COUNT     to ttl(minutes = 5),
            CACHE_CATEGORY_CODES to ttl(hours = 12),
        )

        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(jsonSerializer)
            )
            .disableCachingNullValues()

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(defaultConfig)
            .withInitialCacheConfigurations(
                configurations.mapValues { (_, duration) ->
                    defaultConfig.entryTtl(duration)
                }
            )
            .build()
    }

    @Bean
    fun redisTemplate(redisConnectionFactory: RedisConnectionFactory): RedisTemplate<String, Any> {
        return RedisTemplate<String, Any>().apply {
            connectionFactory = redisConnectionFactory
            keySerializer = StringRedisSerializer()
            valueSerializer = GenericJackson2JsonRedisSerializer()
            hashKeySerializer = StringRedisSerializer()
            hashValueSerializer = GenericJackson2JsonRedisSerializer()
        }
    }

    private fun ttl(minutes: Long = 0, hours: Long = 0): Duration =
        Duration.ofMinutes(minutes + hours * 60)
}
```

