### 5-2. 팔로우 관계 배치 캐시 - P1 (N+1 해소)

**문제: 피드 목록 조회 시 각 게시물 작성자에 대해 팔로우 여부를 개별 쿼리**

```kotlin
// Before: 게시물 20개 -> isFollowing 쿼리 20번 추가 발생
@QueryMapping
fun moments(@UserId userId: String, @Argument limit: Int?): List<MomentResponse> {
    val moments = momentService.listMoments(limit ?: 20)
    return moments.map { moment ->
        val isFollowing = followService.isFollowing(userId, moment.authorId) // N번 gRPC 호출
        moment.toResponse(isFollowing = isFollowing)
    }
}
```

**After: 배치 조회 + 캐시 적용**

```kotlin
// {module}/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        private const val FOLLOW_KEY_PREFIX = "follow:status"
    }

    // 단건 캐시 조회
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_FOLLOW_STATUS],
        key = "#followerId + ':' + #followingId",
    )
    fun isFollowing(followerId: String, followingId: String): Boolean {
        return followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)
    }

    // 배치 캐시 조회 - RedisTemplate으로 파이프라인 처리
    fun isFollowingBatch(followerId: String, targetIds: List<String>): Map<String, Boolean> {
        val keys = targetIds.map { "$FOLLOW_KEY_PREFIX::$followerId:$it" }

        // Redis pipeline으로 한 번에 조회 (RTT 1회)
        val cachedResults = redisTemplate.executePipelined { connection ->
            keys.forEach { key ->
                connection.stringCommands().get(key.toByteArray())
            }
        }

        val resultMap = mutableMapOf<String, Boolean>()
        val missedTargetIds = mutableListOf<String>()

        targetIds.forEachIndexed { index, targetId ->
            val cached = cachedResults[index] as? String
            if (cached != null) {
                resultMap[targetId] = cached.toBoolean()
            } else {
                missedTargetIds.add(targetId)
            }
        }

        // Cache miss 대상만 DB 배치 조회 (IN 쿼리 1번)
        if (missedTargetIds.isNotEmpty()) {
            val dbResults = followRepository
                .findFollowingIds(followerId, missedTargetIds)
                .toSet()

            missedTargetIds.forEach { targetId ->
                val isFollowing = dbResults.contains(targetId)
                resultMap[targetId] = isFollowing

                // 개별 캐시 저장
                redisTemplate.opsForValue().set(
                    "$FOLLOW_KEY_PREFIX::$followerId:$targetId",
                    isFollowing.toString(),
                    Duration.ofMinutes(10),
                )
            }
        }

        return resultMap
    }

    // 팔로우 시 캐시 갱신
    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_FOLLOW_STATUS],
        key = "#followerId + ':' + #followingId",
    )
    @Transactional
    fun follow(followerId: String, followingId: String) {
        followRepository.save(FollowEntity(followerId = followerId, followingId = followingId))
    }

    // 언팔로우 시 캐시 제거
    @CacheEvict(
        cacheNames = [CacheConfig.CACHE_FOLLOW_STATUS],
        key = "#followerId + ':' + #followingId",
    )
    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
    }
}
```

**Repository 수정 (IN 쿼리로 배치 처리):**

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt
interface FollowRepository : JpaRepository<FollowEntity, String> {
    fun existsByFollowerIdAndFollowingId(followerId: String, followingId: String): Boolean

    @Query("""
        SELECT f.followingId FROM FollowEntity f
        WHERE f.followerId = :followerId
          AND f.followingId IN :followingIds
    """)
    fun findFollowingIds(followerId: String, followingIds: List<String>): List<String>
}
```

**예상 개선 수치:**
- 피드 20개 기준 쿼리 수: 21건 -> 최대 2건 (캐시 조회 1번 + DB IN 쿼리 1번)
- 응답 시간: 800ms -> 80ms (약 90% 단축)

