### 5-4. 알림 설정 - P1 (장시간 TTL + 명시적 evict)

```kotlin
// {module}/src/main/kotlin/com/maum/backend/service/notification/NotificationSettingService.kt
@Service
class NotificationSettingService(
    private val notificationSettingRepository: NotificationSettingRepository,
) {
    @Cacheable(
        cacheNames = [CacheConfig.CACHE_NOTIF_SETTING],
        key = "#userId",
    )
    fun getSettings(userId: String): NotificationSettingDto {
        val setting = notificationSettingRepository.findByUserId(userId)
            ?: NotificationSettingDto.default(userId)
        return NotificationSettingDto.from(setting)
    }

    @CachePut(
        cacheNames = [CacheConfig.CACHE_NOTIF_SETTING],
        key = "#userId",
    )
    @Transactional
    fun updateSettings(userId: String, request: UpdateNotificationSettingRequest): NotificationSettingDto {
        val setting = notificationSettingRepository.findByUserId(userId)
            ?: notificationSettingRepository.save(NotificationSettingEntity(userId = userId))

        setting.update(
            callEnabled = request.callEnabled,
            followEnabled = request.followEnabled,
            momentEnabled = request.momentEnabled,
        )
        notificationSettingRepository.save(setting)

        return NotificationSettingDto.from(setting)
        // @CachePut이므로 반환값이 자동으로 캐시에 저장됨
    }
}
